[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<table style="width: 100%; margin-bottom: 1px; margin-right: 0.2in;">
  <tr>
    <!-- Left Cell -->
    <td style="width: 40%; vertical-align: top; padding: 0;">
      <div>
        <!-- Left cell content if needed -->
      </div>
    </td>

    <!-- Center Title Cell -->
    <td style="width: 20%; text-align: center; vertical-align: top;">
      <h2 style="margin: 0; font-size: 16px;">
        <strong>EXPORT INVOICE</strong>
      </h2>
    </td>

    <!-- Spacer -->
    <td style="width: 2%;"></td>


    <!-- Right Info Block -->
    <td style="width: 38%; font-size: 10px; vertical-align: top; padding: 0; margin: 0;">
      <table style="width: 100%; border-collapse: collapse; border-spacing: 0;">
        <tr>
          <td style="width: 75%; padding: 0; font-size: inherit; line-height: 0.75;">
            <div style="margin: 0;">
              <strong>Inv. No. & Dt:</strong> {{ doc.name }}
            </div>
          </td>
          <td style="width: 25%; text-align: right; padding: 0; font-size: inherit; line-height: 0.75;">
            {{ doc.posting_date or '' }}
          </td>
        </tr>

        {% set ns = namespace(delivery_note="", delivery_note_date="") %}

        {% for row in doc.items %}
        {% if not ns.delivery_note and row.delivery_note %}
        {% set ns.delivery_note = row.delivery_note %}
        {% set ns.delivery_note_date = frappe.db.get_value("Delivery Note", row.delivery_note, "posting_date") %}
        {% endif %}
        {% endfor %}

        {% if ns.delivery_note %}
        <tr>
          <td style="width: 75%; padding: 0; font-size: inherit; line-height: 0.75;">
            <div style="margin: 0;">
              <strong>PS.Inv.& Dt:</strong> {{ ns.delivery_note }}
            </div>
          </td>
          <td style="width: 25%; text-align: right; padding: 0; font-size: inherit; line-height: 0.75;">
            {{ ns.delivery_note_date or '' }}
          </td>
        </tr>
        {% endif %}


        {% if doc.po_no or doc.po_date %}
        <tr>
          <td style="width: 75%; padding: 0; font-size: inherit; line-height: 0.75;">
            <div style="margin: 0;">
              <strong>PO No. & Dt:</strong>
              {% if doc.po_no %} {{ doc.po_no }} {% endif %}
            </div>
          </td>
          <td style="width: 25%; text-align: right; padding: 0; font-size: inherit; line-height: 0.75;">
            {% if doc.po_date %} {{ doc.po_date }} {% endif %}
          </td>
        </tr>
        {% endif %}
      </table>
    </td>
  </tr>
</table>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<div style="width: 100%; font-size: 11px; margin-bottom: 8px;">
  <!-- Export / Consignor & Company Name -->
  <div style="text-align: left;">
    <!--<div><strong>Export / Consignor</strong></div>-->
    <div style="font-size: 14px; font-weight: bold;">{{ doc.company }}</div>
  </div>
  {% set company_doc = frappe.get_doc("Company", doc.company) %}
  <!-- Two-column layout using flex -->
  <div style="display: flex; gap: 2%; margin-top: 6px;">
    <!-- Block 1: Billed From -->
    <div style="flex: 1;">
      <div style="font-size: 11px; font-weight: bold;">(Billed From)</div>
      {% if doc.company_address %}
      {% set addr = frappe.get_doc("Address", doc.company_address) %}
      {{ addr.address_line1 }}<br>
      {% if addr.address_line2 %}{{ addr.address_line2 }}<br>{% endif %}
      {{ addr.city }}{% if addr.state %}, {{ addr.state }}{% endif %}, {{ addr.country }}<br>

      <div style="margin-top: 5px;"></div>
      {% if addr.email_id %}<strong>Email:</strong> {{ addr.email_id }}<br>{% endif %}
      {% if addr.phone %}<strong>Phone:</strong> {{ addr.phone }}<br>{% endif %}
      {% if addr.gstin %}<strong>GSTIN:</strong> {{ addr.gstin }}<br>{% endif %}
      {% if doc.is_export_with_gst == 0 and company_doc.custom_lut %}<strong>LUT #:</strong> {{ company_doc.custom_lut
      }}<br>{% endif %}
      {% endif %}
    </div>

    <!-- Block 2: Supply From -->
    <div style="flex: 1;">
      <div style="font-size: 11px; font-weight: bold;">(Supply From)</div>
      {% if doc.dispatch_address_name %}
      {% set addr = frappe.get_doc("Address", doc.dispatch_address_name) %}
      {{ addr.address_line1 }}<br>
      {% if addr.address_line2 %}{{ addr.address_line2 }}<br>{% endif %}
      {{ addr.city }}{% if addr.state %}, {{ addr.state }}{% endif %}, {{ addr.country }}<br>

      <div style="margin-top: 5px;"></div>
      {% if addr.custom_dl_1 %}<strong>DL No 1:</strong> {{ addr.custom_dl_1 }}<br>{% endif %}
      {% if addr.custom_dl_2 %}<strong>DL No 2:</strong> {{ addr.custom_dl_2 }}<br>{% endif %}
      {% if company_doc.custom_ie_code %}<strong>IE Code:</strong> {{ company_doc.custom_ie_code }}<br>{% endif %}
      {% endif %}
    </div>
  </div>

  <!-- Two-column layout using flex -->
  <div style="display: flex; gap: 2%; margin-top: 6px;">
    <div style="flex: 1;">
      <div><strong>Pre-carriage by:</strong></div>
      <div style="font-size: 11px;">{% if doc.mode_of_transport %}{{ doc.mode_of_transport }}{% endif %}</div>
      <div><strong>Vessel/Flight No.</strong></div>
      <div style="font-size: 11px;">{% if doc.vehicle_no %}{{ doc.vehicle_no }}{% endif %}</div>
    </div>

    <div style="flex: 1;">
      <div><strong>Place of Receipt by Pre-carrier:</strong></div>
      <div style="font-size: 11px;">{% if doc.custom__precarrier_place %}{{ doc.custom__precarrier_place }}{% endif %}
      </div>
      <div><strong>Notify Party:</strong></div>
      <div style="font-size: 11px;">{% if doc.custom_notify_party %}{{ doc.custom_notify_party }}{% endif %}</div>
    </div>
  </div>

  <div style="display: flex; gap: 2%; margin-top: 6px;">
    <div style="flex: 1;">
      <div><strong>Other Reference(s): </strong></div>
      <div style="font-size: 11px;">{% if doc.custom_references %}{{ doc.custom_references }}{% endif %}</div>
    </div>
  </div>
</div>"}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<div style="width: 100%; font-size: 11px; margin-bottom: 8px;">
  <!-- Consignee & Company Name -->
  <div style="text-align: left;">
    <!--<div><strong>Consignee</strong></div>-->
    {% if doc.custom_display_origin_port_address_as_ship_to == 0 %}
    <div style="font-size: 14px; font-weight: bold;">{{ doc.customer }}</div>
    {% else %}
    <div>&nbsp;</div>
    {% endif %}
  </div>

  <!-- Two-column layout using flex -->
  <div style="display: flex; gap: 2%; margin-top: 6px;">
    <!-- Block 1: Consignee -->
    <div style="flex: 1;">
      <div><strong>(Bill To)</strong></div>
      {% if doc.customer_address %}
      {% if doc.custom_display_origin_port_address_as_ship_to == 1 %}
      <p style="font-size: 12px;"><b>{{ doc.customer }}</b></p>
      {% endif %}
      {% set consignee_addr = frappe.get_doc("Address", doc.customer_address) %}
      {{ consignee_addr.address_line1 }}<br>
      {% if consignee_addr.address_line2 %}{{ consignee_addr.address_line2 }}<br>{% endif %}
      {{ consignee_addr.city }}{% if consignee_addr.state %}, {{ consignee_addr.state }}{% endif %}, {{
      consignee_addr.country }}<br>
      {% endif %}
    </div>

    <!-- Block 2: Buyer (if other than Consignee) -->
    <div style="flex: 1;">
      <div><strong>(Ship To)</strong></div>

      {% if doc.custom_display_origin_port_address_as_ship_to == 1 %}
      {% if doc.port_address %}
      {% set address = frappe.get_doc("Address", doc.port_address) %}
      {% set link_name = address.links[0].link_title if address.links and address.links[0] else None %}
      <p style="font-size: 12px;"><b>{{ link_title or address.address_title }}</b></p>
      {{ address.address_line1 }}<br>
      {% if address.address_line2 %}{{ address.address_line2 }}<br>{% endif %}
      {{ address.city }}{% if address.state %}, {{ address.state }}{% endif %}, {{ address.country }}<br>
      {% endif %}
      {% else %}
      {% if doc.shipping_address_name %}
      {% set buyer_addr = frappe.get_doc("Address", doc.shipping_address_name) %}
      <!-- <p style="font-size: 13px;"><b>{{ doc.customer }}</b></p> -->
      {{ buyer_addr.address_line1 }}<br>
      {% if buyer_addr.address_line2 %}{{ buyer_addr.address_line2 }}<br>{% endif %}
      {{ buyer_addr.city }}{% if buyer_addr.state %}, {{ buyer_addr.state }}{% endif %}, {{ buyer_addr.country }}<br>
      {% endif %}
      {% endif %}
    </div>

  </div>

  <div style="display: flex; gap: 2%; margin-top: 6px;">
    <!-- Block 1 -->
    <div style="flex: 1;">
      <div><strong>Country of Origin of Goods:</strong></div>
      <div>{% if doc.custom_origin_country %}{{ doc.custom_origin_country }}{% endif %}</div>

      <div><strong>Port of Loading:</strong></div>
      <div>{% if doc.port_code %}{{ doc.port_code }}{% endif %}</div>
    </div>

    <!-- Block 2 -->
    <div style="flex: 1;">
      <div><strong>Country of Final Destination:</strong></div>
      <div>{% if doc.custom_destination_country %}{{ doc.custom_destination_country }}{% endif %}</div>

      <div><strong>Port of Discharge:</strong></div>
      <div>
        {% if doc.custom_port_of_discharge %}
        {% set port = frappe.get_doc("Port", doc.custom_port_of_discharge) %}
        {{ port.port_name }} ({{ port.port_code }})
        {% endif %}
      </div>
    </div>
  </div>

  <div style="display: flex; gap: 2%; margin-top: 6px;">
    <!-- Block 1 -->
    <div style="flex: 1;">
      <div><strong>Terms of Delivery:</strong></div>
      <div>{% if doc.incoterm %}{{ doc.incoterm }}{% endif %}</div>

      <div><strong>Inco Place:</strong></div>
      <div>{% if doc.named_place %}{{ doc.named_place }}{% endif %}</div>
    </div>

    <!-- Block 2 -->
    <div style="flex: 1;">
      <div><strong>Terms of Payment:</strong></div>
      <div>{% if doc.custom_payment_terms %}{{ doc.custom_payment_terms }}{% endif %}</div>
    </div>
  </div>
</div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
  .compact-item-table {
    font-size: 10px;
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
    margin-top: 25px;
    margin-bottom: 25px;
  }

  .compact-item-table th,
  .compact-item-table td {
    padding: 4px 2px;
    border: 1px solid #ccc;
    text-align: left;
    vertical-align: top;
    word-wrap: break-word;
  }

  .item-title {
    font-weight: bold;
    margin-bottom: 4px;
    word-wrap: break-word;
  }

  .sub-header-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 9px;
    /* margin: 2px; */
    border: none;
  }

  .sub-header-table th {
    border: none;
    /* padding: 2px; */
    font-weight: normal;
    text-align: left;
  }

  .sub-row-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 9px;
    margin-top: 4px;
    border: none;
  }

  .sub-row-table td {
    /* padding: 2px; */
    border: none;
    text-align: left;
    font-weight: normal;
  }

  .text-right {
    text-align: right !important;
  }

  .text-left {
    text-align: left !important;
  }
</style>

<table class="compact-item-table">
  <thead>
    <tr>
      <th style="width: 4%;">#</th>
      <th style="width: 50%;">
        <div><strong>Description of Goods</strong> &nbsp;&nbsp; WESTERN DRUGS AND HARMLESS MEDICINES</div>
        <table class="sub-header-table">
          <tr>
            <th style="width: 20%; padding-left: 0 !important;">Pck. Slip<br>Ref</th>
            <th style="width: 15%; padding-left: 0 !important;">Pck.<br>Nos.</th>
            <th style="width: 15%; padding-left: 0 !important;">Batch<br>No.</th>
            <th style="width: 2.5%; padding-left: 0 !important;"></th>
            <th style="width: 10%; padding-left: 0 !important;">Mfg.<br>Dt</th>
            <th style="width: 2.5%; padding-left: 0 !important;"></th>
            <th style="width: 10%; padding-left: 0 !important;">Exp.<br>Dt</th>
            <th style="width: 10%; padding-left: 0 !important;"></th>
            <th style="width: 15%; padding-left: 0 !important;">Qty</th>
          </tr>
        </table>
      </th>
      <th style="width: 8%;">HSN<br>CODE</th>
      <th style="width: 6%;">Pck.<br>Type</th>
      <th style="width: 8%;">Pck.<br>Style</th>
      <th style="width: 9%;">Total Qty</th>
      <th style="width: 6%;">Unit<br>Rate<br>({{ doc.currency }})</th>
      <th style="width: 9%;">Amount<br>({{ doc.currency }})</th>
    </tr>
  </thead>
  <tbody>
    {% for item in doc.items %}
    <tr>
      <td>{{ loop.index }}</td>
      <td>
        <div class="item-title">{{ item.item_name }}</div>
        <!-- <div>Type: {{ item.custom_pack_style or '' }}</div> -->
         {% set pack_style = frappe.db.get_value("Item", item.item_code, "custom_pack_style") if item.item_code else "" %}
        <table class="sub-row-table">
          <tbody>
            {% for pack in doc.custom_packaged_items if pack.item_code == item.item_code %}
            {% set batch = pack.batch %}
            {% set mfg_date = frappe.db.get_value("Batch", batch, "manufacturing_date") if batch else "" %}
            {% set exp_date = frappe.db.get_value("Batch", batch, "expiry_date") if batch else "" %}
            <tr>
              <td style="width: 20%; padding-left: 0 !important;">{{ pack.packing_slip_reference or '' }}</td>
              <td style="width: 15%; padding-left: 0 !important;">{{ pack.pack_nos_range or '' }}</td>
              <td style="width: 15%; padding-left: 0 !important;">{{ batch or '' }}</td>
              <td style="width: 2.5%; padding-left: 0 !important;"></td>
              <td style="width: 10%; padding-left: 0 !important;">{{ frappe.utils.format_date(mfg_date, "MM/yyyy") if
                mfg_date else "" }}</td>
                <td style="width: 2.5%; padding-left: 0 !important;"></td>
              <td style="width: 10%; padding-left: 0 !important;">{{ frappe.utils.format_date(exp_date, "MM/yyyy") if
                exp_date else "" }}</td>
              <td style="width: 10%; padding-left: 0 !important;"></td>
              <td style="width: 15%; padding-left: 0 !important;">{{ pack.qty or '' }}&nbsp;&nbsp;{{ pack.stock_uom or
                '' }}</td>
            </tr>
            {% endfor %}
          </tbody>
        </table>
      </td>
      <td class="text-left">{{ item.gst_hsn_code or '' }}</td>
      <td class="text-left">{{ item.uom or '' }}</td>
      <td class="text-left">{{ pack_style or '' }}</td>
      <td class="text-right">{{ item.qty or 0 }}</td>
      <td class="text-right">{{ item.rate or 0 | round(2) }}</td>
      <td class="text-right">{{ item.amount or 0 | round(2) }}</td>
    </tr>
    {% endfor %}
  </tbody>
</table>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<div style="display: flex; gap: 2%; margin-top: 6px; font-size: 14px">
    <!-- Block 1 -->
    <div style="flex: 1;">
      <b>Total ({{ doc.currency }}):</b>
    </div>

    <!-- Block 2 -->
    <div style="flex: 1;">
      <span>{{ frappe.utils.fmt_money(doc.total, currency=doc.currency) }}</span>
    </div>
  </div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<p style="font-size: 14px; font-weight: bold; margin-top: 20px; padding: 0">
    <b>Total in words :</b>
    {{ frappe.utils.money_in_words(doc.total, doc.currency) }}
</p>"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
  .bottom-table {
    width: 100%;
    border-collapse: collapse;
    page-break-inside: avoid; /* 👈 Prevents breaking mid-table */
    font-size: 10px;
    /*font-family: Arial, sans-serif;*/
    /*position: fixed;*/
    /*bottom: 0;*/
    /*left: 0;*/
    /*right: 0;*/
  }

  .terms {
    vertical-align: top;
    padding: 5px;
    border-top: 1px solid #000;
    width: 70%;
  }

  .terms p {
    margin: 1px 0;
    line-height: 1;
  }

  .signature {
    vertical-align: top;
    text-align: right;
    padding: 5px;
    width: 30%;
    border-top: 1px solid #000;
    white-space: nowrap;
  }

  .signature .company {
    font-weight: bold;
    margin-bottom: 40px;
  }

  .no-break {
    page-break-inside: avoid;
    break-inside: avoid;
  }
</style>

<table class="bottom-table no-break">
  <tr>
    <td class="terms">
      <p><strong>Declaration:</strong></p>
      <p>We declare that the goods described and all particulars are true and correct.<br>
'WE INTEND TO CLAIM REWARDS UNDER :<br>
REMISSION OF DUTIES OR TAXES<br>
ON EXPORTED PRODUCTS (RODTEP)'</p>
    </td>
    <td class="signature">
      <div class="company">For {{ doc.company }}</div>
      <div>Authorised Signatory</div>
    </td>
  </tr>
</table>
"}]
